import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faSearch } from '@fortawesome/free-solid-svg-icons';

const App = () => {
  const [query, setQuery] = useState('');
  const [metrics, setMetrics] = useState('accuracy');
  const [tokens, setTokens] = useState(0);

  const handleSearch = (e) => {
    setQuery(e.target.value);
  };

  const handleMetricsChange = (e) => {
    setMetrics(e.target.value);
  };

  const handleTokensChange = (e) => {
    setTokens(e.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="flex flex-col md:flex-row items-center mb-4">
        <div className="flex-1 md:ml-4">
          <input
            type="search"
            className="block w-full px-4 py-2 text-sm text-gray-700 placeholder-gray-500 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
            placeholder="Search models..." onChange={handleSearch}
          />
        </div>
        <div className="flex-1 md:ml-4">
          <select
            className="block w-full px-4 py-2 text-sm text-gray-700 placeholder-gray-500 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
            value={metrics} onChange={handleMetricsChange}
          >
            <option value="accuracy">Accuracy</option>
            <option value="precision">Precision</option>
            <option value="recall">Recall</option>
          </select>
        </div>
        <div className="flex-1 md:ml-4">
          <input
            type="number"
            className="block w-full px-4 py-2 text-sm text-gray-700 placeholder-gray-500 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
            value={tokens} onChange={handleTokensChange}
          />
        </div>
      </div>
      {/* TODO: Implement performance charts and token tracker */}
    </div>
  );
};

export default App;
